import play.api.mvc._
import javax.inject.Inject
import scala.concurrent.ExecutionContext.Implicits.global
import slick.jdbc.PostgresProfile.api._
import scala.concurrent.Future

case class Product(id: Int, name: String, price: Double)

class ProductController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  def searchProducts = Action.async { request =>
    val sqlQuery = buildProductSearchQuery(request.queryString)
    db.run(sqlQuery.result).map { products =>
      Ok(views.html.products(products))
    }
  }

  private def buildProductSearchQuery(params: Map[String, Seq[String]]): Query[_, Product, Seq] = {
    var query = sql"SELECT * FROM products WHERE 1=1"
    params.get("name").foreach(name => query += sql" AND name LIKE ${s"%${name.head}%"}")
    params.get("minPrice").map(_.head.toDouble).foreach(minPrice => query += sql" AND price >= $minPrice")
    params.get("maxPrice").map(_.head.toDouble).foreach(maxPrice => query += sql" AND price <= $maxPrice")
    query.as[Product]
  }

  val db = Database.forConfig("mydb")
}